	}
	if got.ModelRef != "claude-mref" {
		t.Errorf("ModelRef = %q, want %q", got.ModelRef, "claude-mref")
	}
	if got.Effort != "high" {
		t.Errorf("Effort = %q, want %q", got.Effort, "high")
	}
}

